      emitter
      and emitter.enabled
      and emitter.system
      and (not instance.systemIndex or instance.systemIndex == index)
    then
      TimelineRuntime.applyTimelineToEmitter(emitter, track, time, allowEmission == true, {
        base = emitter.base or {},
        directionOffset = instance.directionOffset or 0,
        opacityField = "opacity",
      })
    end
  end
end

