      and emitter.enabled
      and emitter.system
      and (not instance.systemIndex or instance.systemIndex == index)
    then
      for _, clip in ipairs(track.clips or {}) do
        local start = tonumber(clip.start) or 0
        if previousTime <= start and nextTime >= start then
          local count = clipBurstCount(clip, emitter)
          emitter.system:setEmitterLifetime((emitter.base and emitter.base.emitterLifetime) or -1)
          emitter.system:start()
          if count > 0 then
            emitter.system:emit(count)
          end
        end
      end
    end
  end
end

local function emitTimelineStartsForAdvance(instance, previousTime, elapsed)
  if elapsed <= 0 then
    return previousTime
  end
  local cursor = previousTime
  local remaining = elapsed
  local guard = 0
  while remaining > 0 and guard < 128 do
    if cursor >= timeline.duration then
      cursor = 0
    end
    local room = math.max(0, timeline.duration - cursor)
    if room <= 0 then
      cursor = 0
      room = timeline.duration
    end
    local segment = math.min(remaining, room)
    local nextCursor = cursor + segment
    if segment > 0 then
      emitTimelineStarts(instance, cursor, nextCursor)
    end
    remaining = remaining - segment
    cursor = nextCursor
    if remaining > 0 and cursor >= timeline.duration then
      cursor = 0
    end
    guard = guard + 1
  end
  return cursor >= timeline.duration and 0 or cursor
end

local function timelineShouldLoop(instance)
  if instance and instance.loop ~= nil then
    return instance.loop == true
  end
  if timelineState.loop ~= nil then
    return timelineState.loop == true
  end
  return timeline.loop == true
end

local function setLoop(loop)
  if type(loop) == "boolean" then
    timelineState.loop = loop
  else
    timelineState.loop = nil
  end
  for _, instance in ipairs(activeInstances) do
    instance.loop = timelineState.loop
  end
  return timelineShouldLoop(nil)
end

local function resetInstance(instance, payload)
  payload = type(payload) == "table" and payload or {}
  local x = tonumber(payload.x) or particles.x
  local y = tonumber(payload.y) or particles.y
  instance.time = 0
  instance.playing = true
  instance.active = true
  if type(payload.loop) == "boolean" then
    instance.loop = payload.loop
  else
    instance.loop = timelineState.loop
  end
  instance.directionOffset = tonumber(payload.r) or 0
  instance.systemIndex = tonumber(payload.systemIndex)
  for index, emitter in ipairs(instance.systems or {}) do
    local participates = not instance.systemIndex or instance.systemIndex == index
    if emitter.enabled and emitter.system then
      emitter.system:reset()
      emitter.system:setEmitterLifetime((emitter.base and emitter.base.emitterLifetime) or -1)
      emitter.system:setPosition(x + (emitter.x or 0), y + (emitter.y or 0))
      emitter.opacity = participates and 1 or 0
      if participates then
        emitter.system:start()
      else
        emitter.system:setEmissionRate(0)
        emitter.system:stop()
      end
    end
  end
  applyTimeline(instance, 0, true)
  emitTimelineStarts(instance, 0, 0)
  return instance
end

local function recycleInstance(instance)
  if not instance then
    return
  end
  instance.active = false
  instance.playing = false
  instance.time = 0
  instance.loop = nil
  instance.directionOffset = 0
  instance.systemIndex = nil
  for _, emitter in ipairs(instance.systems or {}) do
    if emitter.system then
      emitter.system:reset()
      emitter.system:setEmissionRate(0)
      emitter.system:setEmitterLifetime((emitter.base and emitter.base.emitterLifetime) or -1)
    end
    emitter.opacity = 1
  end
  if #pooledInstances < MAX_POOLED_INSTANCES then
    pooledInstances[#pooledInstances + 1] = instance
  else
    releaseInstance(instance)
  end
end

local function checkoutInstance(payload)
  local instance = table.remove(pooledInstances)
  if not instance then
    instance = createInstance()
  end
  activeInstances[#activeInstances + 1] = instance
  resetInstance(instance, payload)
  publishSystems(instance)
  return instance
end

local function instanceHasParticles(instance)
  for _, emitter in ipairs(instance.systems or {}) do
    if emitter.enabled and emitter.system then
      local ok, count = pcall(emitter.system.getCount, emitter.system)
      if ok and (tonumber(count) or 0) > 0 then
        return true
      end
    end
  end
  return false
end

local function update(dt)
  for i = #activeInstances, 1, -1 do
    local instance = activeInstances[i]
    if instance.playing then
      local previous = instance.time
      local nextTime = previous + dt
      if nextTime > timeline.duration then
        if timelineShouldLoop(instance) then
          nextTime = emitTimelineStartsForAdvance(instance, previous, dt)
        else
          emitTimelineStarts(instance, previous, timeline.duration)
          nextTime = timeline.duration
          instance.playing = false
        end
      else
        emitTimelineStarts(instance, previous, nextTime)
      end
      instance.time = nextTime
    end
    applyTimeline(instance, instance.time, instance.playing)
    for index, emitter in ipairs(instance.systems or {}) do
      if emitter.enabled and emitter.system and (not instance.systemIndex or instance.systemIndex == index) then
        emitter.system:update(dt)
      end
    end
    if not instance.playing and not instanceHasParticles(instance) then
      table.remove(activeInstances, i)
      recycleInstance(instance)
    end
  end
  local latest = activeInstances[#activeInstances]
  timelineState.time = latest and latest.time or 0
  timelineState.playing = latest and latest.playing or false
  timelineState.directionOffset = latest and latest.directionOffset or 0
end

local function draw()
  local previousBlend, previousAlphaMode = LG.getBlendMode()
  local previousShader = LG.getShader()
  local r, g, b, a = LG.getColor()

  for _, instance in ipairs(activeInstances) do
    for index, emitter in ipairs(instance.systems or {}) do
      if emitter.enabled and emitter.system and (not instance.systemIndex or instance.systemIndex == index) then
        LG.setBlendMode(emitter.blendMode or "alpha")
        if emitter.shader and emitter.shader.send and love.timer then
          pcall(emitter.shader.send, emitter.shader, "u_time", love.timer.getTime())
        end
        LG.setShader(emitter.shader)
        LG.setColor(1, 1, 1, emitter.opacity or 1)
        LG.draw(emitter.system, 0, 0)
      end
    end
  end

  LG.setBlendMode(previousBlend, previousAlphaMode)
  LG.setShader(previousShader)
  LG.setColor(r, g, b, a)
end

---Play the authored particle timeline.
---@param payload ParticlePayload
local function play(payload)
  if type(payload) ~= "table" then
    payload = {}
  end
  return checkoutInstance(payload)
end

local function pause()
  timelineState.playing = false
  for _, instance in ipairs(activeInstances) do
    instance.playing = false
    applyTimeline(instance, instance.time, false)
  end
  return true
end

local function stop(resetParticles)
  timelineState.time = 0
  timelineState.playing = false
  timelineState.loop = nil
  timelineState.directionOffset = 0
  for i = #activeInstances, 1, -1 do
    local instance = activeInstances[i]
    instance.playing = false
    instance.loop = nil
    instance.directionOffset = 0
    applyTimeline(instance, instance.time or 0, false)
    if resetParticles ~= false then
      table.remove(activeInstances, i)
      recycleInstance(instance)
    end
  end
  if resetParticles ~= false then
    publishSystems(nil)
  end
  return true
end

local function emit(payload)
  return play(payload)
end

release = function()
  for i = #activeInstances, 1, -1 do
    releaseInstance(activeInstances[i])
    activeInstances[i] = nil
  end
  for i = #pooledInstances, 1, -1 do
    releaseInstance(pooledInstances[i])
    pooledInstances[i] = nil
  end
  clearSystemsAlias()
  return true
end

return {
  init = init,
  draw = draw,
  update = update,
  play = play,
  pause = pause,
  stop = stop,
  setLoop = setLoop,
  isLooping = timelineShouldLoop,
  emit = emit,
  release = release,
}
